class Solution:
    def countDistinctIntegers(self, nums):
        # build the full extended list explicitly, then count uniques
        extended = list(nums)
        for v in nums:
            extended.append(int(str(v)[::-1]))
        unique = []
        seen_flag = {}
        for x in extended:
            if x not in seen_flag:
                seen_flag[x] = True
                unique.append(x)
        return len(unique)

