class Solution:
    def countDistinctIntegers(self, nums):
        seen = set()
        for v in nums:
            seen.add(v)
            r = 0
            x = v
            while x > 0:
                r = r * 10 + x % 10
                x //= 10
            seen.add(r)
        return len(seen)

