var countDistinctIntegers = function(nums) {
    const seen = new Set();
    for (const v of nums) {
        seen.add(v);
        let r = 0;
        let x = v;
        while (x > 0) {
            r = r * 10 + (x % 10);
            x = Math.floor(x / 10);
        }
        seen.add(r);
    }
    return seen.size;
};
